import React from "react";
import DeckCard from './Card';

function Decks({ decks, handleDeleteDeck, loadCards }) {
  return decks.map((deck, index) => {
    return (
      <DeckCard deck={deck} loadCards={loadCards} handleDeleteDeck={handleDeleteDeck} index={index} />
    );
  });
}

export default Decks;
